# Resolvers
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> ProductType:
        db = next(get_db())
        return db.query(Product).filter(Product.id == id).first()
    
    @strawberry.field
    def products(self, info, limit: int = 100, offset: int = 0) -> list[ProductType]:
        db = next(get_db())
        return db.query(Product).offset(offset).limit(limit).all()
    
    @strawberry.field
    def category(self, info, id: int) -> CategoryType:
        db = next(get_db())
        return db.query(Category).filter(Category.id == id).first()
    
    @strawberry.field
    def categories(self, info) -> list[CategoryType]:
        db = next(get_db())
        return db.query(Category).all()

# Security
def validate_query(query_string: str, max_depth: int = 10, max_complexity: int = 1000):
    """Validate query to prevent malicious queries"""
    if not query_string:
        return False
    
    # Simple depth check
    depth = 0
    max_depth_reached = False
    
    for char in query_string:
        if char == '{':
            depth += 1
            if depth > max_depth:
                max_depth_reached = True
                break
        elif char == '}':
            depth -= 1
    
    if max_depth_reached:
        return False
    
    # Complexity check - basic implementation
    complexity = query_string.count('{') + query_string.count('}') + query_string.count('...')
    if complexity > max_complexity:
        return False
    
    return True

# GraphQL Schema
schema = strawberry.Schema(query=Query)

# FastAPI App
app = FastAPI()
graphql_app = GraphQLRouter(schema=schema, context_getter=get_db)
app.include_router(graphql_app, prefix="/graphql")

